// Calcula rangos de fechas en zona Europe/Madrid (ISO week: lunes-domingo)
const now = new Date();

function madridYMD(d){ return d.toLocaleDateString('en-CA', { timeZone:'Europe/Madrid' }); }
function madridDow(d){
  // 0=Lun ... 6=Dom
  const wd = new Intl.DateTimeFormat('en-US', { timeZone:'Europe/Madrid', weekday:'short' }).format(d);
  return ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].indexOf(wd);
}
function ymdToDate(s){ return new Date(s + 'T00:00:00Z'); }
function ymdFromDate(d){ return d.toISOString().substring(0,10); }
function addDays(s,n){ const d = ymdToDate(s); d.setUTCDate(d.getUTCDate()+n); return ymdFromDate(d); }

const todayYMD     = madridYMD(now);
const daysSinceMon = madridDow(now);
const weekYMD      = addDays(todayYMD, -daysSinceMon);
const lastWeekYMD  = addDays(weekYMD, -7);
const yesterdayYMD = addDays(todayYMD, -1);
const sevenDaysYMD = addDays(todayYMD, -6);
const [yy, mm]     = todayYMD.split('-');
const monthYMD     = `${yy}-${mm}-01`;
// Histórico para medias y sparklines: ahora 56 días atrás → 8 mismos días
// de semana para la media. Se fetcha en 2 chunks (recent 0-28d + older 28-56d)
// para mantener cada query por debajo del límite de 1000 del Search API.
const histYMD       = addDays(todayYMD, -28);   // weeks 1-4 (recent)
const histOlderYMD  = addDays(todayYMD, -56);   // weeks 5-8 (older) — start del rango
const agedYMD       = addDays(todayYMD, -5);    // umbral 'lleva más de 5 días'

return [{ json: {
  today_ymd:        todayYMD,
  yesterday_ymd:    yesterdayYMD,
  week_ymd:         weekYMD,
  last_week_ymd:    lastWeekYMD,
  seven_days_ymd:   sevenDaysYMD,
  month_ymd:        monthYMD,
  hist_ymd:         histYMD,
  hist_older_ymd:   histOlderYMD,
  aged_ymd:         agedYMD,
  now_iso:          now.toISOString()
} }];

const prev = $input.first().json;
const dates = $('Calcular fechas').first().json;
return [{ json: { ...dates, zd_today: prev } }];

// Calcula FRT — defensivo, incluye tickets pendientes con el tiempo
// que llevan esperando (minutos desde creación)
let acc = {};
try {
  acc = $('Guardar Hoy Manual').first().json || {};
} catch (e) {
  return [{ json: { _frt_status: 'no_acc:' + (e && e.message || e) } }];
}

let body = {};
try { body = $input.first().json || {}; } catch (e) { body = {}; }

const metrics = Array.isArray(body.ticket_metrics) ? body.ticket_metrics : [];
const bodyKeys = Object.keys(body).slice(0, 10).join(',');

const manualResults = (acc.zd_today_manual && acc.zd_today_manual.results) || [];
const todayManualIds = new Set(
  manualResults.map(t => t && t.id != null ? String(t.id) : null).filter(Boolean)
);
// Mapas auxiliares
const subjectById = new Map();
const createdById = new Map();
for (const t of manualResults) {
  if (t && t.id != null) {
    subjectById.set(String(t.id), t.subject || '');
    createdById.set(String(t.id), t.created_at);
  }
}

const todayMetrics = metrics.filter(m => m && m.ticket_id != null && todayManualIds.has(String(m.ticket_id)));
const nowMs = Date.now();

function effectiveTime(m) {
  const cal = m && m.reply_time_in_minutes && m.reply_time_in_minutes.calendar;
  if (typeof cal === 'number' && cal > 0) return { min: cal, status: 'answered' };
  // Pendiente: tiempo desde creación
  const created = createdById.get(String(m.ticket_id));
  if (!created) return { min: null, status: 'unknown' };
  const elapsed = Math.round((nowMs - new Date(created).getTime()) / 60000);
  return { min: elapsed > 0 ? elapsed : 1, status: 'pending' };
}

// Breakdown completo (todos los manuales hoy)
const _frt_breakdown = todayMetrics.map(m => {
  const tid = String(m.ticket_id);
  const eff = effectiveTime(m);
  return {
    ticket_id: m.ticket_id,
    subject: (subjectById.get(tid) || '').slice(0, 80),
    reply_time_calendar_min: m.reply_time_in_minutes && m.reply_time_in_minutes.calendar,
    reply_time_business_min: m.reply_time_in_minutes && m.reply_time_in_minutes.business,
    effective_min: eff.min,
    state: eff.status,  // 'answered' | 'pending' | 'unknown'
    created_at: createdById.get(tid),
    url: `https://soporteyurest.zendesk.com/agent/tickets/${m.ticket_id}`
  };
}).sort((a,b) => (a.effective_min || 999999) - (b.effective_min || 999999));

// Media SOLO sobre los respondidos (state==='answered').
// Los pendientes se cuentan aparte como info, no entran en el promedio.
const answeredItems = _frt_breakdown.filter(x => x.state === 'answered');
const times = answeredItems.map(x => x.effective_min);
const sample = times.length;
const avgMin = sample ? Math.round(times.reduce((a,b)=>a+b,0) / sample) : null;
const sorted = times.slice().sort((a,b)=>a-b);
const median = sample ? sorted[Math.floor(sample/2)] : null;
const minV = sample ? sorted[0] : null;
const maxV = sample ? sorted[sorted.length-1] : null;

const answered = answeredItems.length;
const pending  = _frt_breakdown.filter(x => x.state === 'pending').length;

return [{ json: {
  ...acc,
  frt_avg_min: avgMin,
  frt_sample: sample,
  frt_answered: answered,
  frt_pending: pending,
  _frt_today_ids_size: todayManualIds.size,
  _frt_metrics_size: metrics.length,
  _frt_matched: todayMetrics.length,
  _frt_status: 'ok',
  _frt_body_keys: bodyKeys,
  _frt_min: minV,
  _frt_max: maxV,
  _frt_median: median,
  _frt_breakdown
} }];

// Recoge todos los tickets envejecidos (Zendesk native emite uno por item)
const acc = $('Calcular FRT').first().json;
const allAged = $input.all().map(i => i.json).filter(Boolean);
return [{ json: { ...acc, zd_aged: { results: allAged, count: allAged.length } } }];

// Recoge todas las incidencias dev (Zendesk native emite uno por item)
const acc = $('Guardar Envejecidos').first().json;
const all = $input.all().map(i => i.json).filter(Boolean);
return [{ json: { ...acc, zd_incidencias: { results: all, count: all.length } } }];

// Solo resuelve nombres de orgs con tickets ABIERTOS ahora (para orgs_by_open_count).
// El top de orgs del mes lo calcula y resuelve el workflow historico.
const d = $input.first().json;
const openRes = (d.zd_open && Array.isArray(d.zd_open.results)) ? d.zd_open.results : [];
const openOrgCount = new Map();
for (const t of openRes) { if(!t.organization_id) continue; openOrgCount.set(t.organization_id,(openOrgCount.get(t.organization_id)||0)+1); }
const ids = [...openOrgCount.entries()].sort((a,b)=>b[1]-a[1]).slice(0,100).map(([id])=>id);
return [{ json: { ...d, org_ids_csv: ids.join(',') || '0' } }];

// Agregar KPIs (live) = datos vivos (de 'Guardar Orgs') + capa historica (Data Table, via $input).
const d = $('Guardar Orgs').first().json;
const histRow = $input.first().json || {};
let hist = {};
try { hist = histRow.payload ? JSON.parse(histRow.payload) : {}; } catch(e) { hist = {}; }

function count(o){ if(!o) return 0; if(typeof o.count==='number') return o.count; if(Array.isArray(o.results)) return o.results.length; return 0; }
function results(o){ return (o && Array.isArray(o.results)) ? o.results : []; }
function ymdMad(date){ return date.toLocaleDateString('en-CA',{timeZone:'Europe/Madrid'}); }
function partsMad(date){ return new Intl.DateTimeFormat('en-US',{timeZone:'Europe/Madrid',weekday:'short',hour:'2-digit',hour12:false}).formatToParts(date); }

const today = count(d.zd_today);
const week = count(d.zd_week);
const open = count(d.zd_open);
const todayIA = count(d.zd_today_ia);
const todayManual = count(d.zd_today_manual);
const solvedToday = count(d.zd_solved_today);
const backlogToday = todayManual - solvedToday;
const todayRes = results(d.zd_today);
const openRes = results(d.zd_open);
const pending = openRes.filter(t => t.status === 'pending').length;

const nowD = new Date();
const todayLocalYMD = ymdMad(nowD);
const todayWdStr = new Intl.DateTimeFormat('en-US',{timeZone:'Europe/Madrid',weekday:'short'}).format(nowD);

// hourly_today: hoy (vivo) + avg (historico)
const HOURS=['09','10','11','12','13','14','15','16','17','18'];
const hoursToday=Object.fromEntries(HOURS.map(h=>[h,0]));
for (const t of todayRes){ if(!t.created_at) continue; const dt=new Date(t.created_at); if(ymdMad(dt)!==todayLocalYMD) continue; const s=String(t.subject||'').trim().toLowerCase(); if(s.startsWith('conversation with')) continue; const hh=partsMad(dt).find(p=>p.type==='hour')?.value||'00'; if(hoursToday[hh]!==undefined) hoursToday[hh]++; }
const avgMap=Object.fromEntries((hist.hourly_avg||[]).map(o=>[String(o.hour).slice(0,2), o.avg]));
const hourly_today=HOURS.map(h=>({ hour:h+':00', today:hoursToday[h], avg: (avgMap[h] ?? 0) }));

// weekly_stacked: historico + parchea hoy con datos vivos
const DAYS=['Lun','Mar','Mié','Jue','Vie'];
const wdIdx=['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].indexOf(todayWdStr);
const todayDayName=(wdIdx>=0&&wdIdx<=4)?DAYS[wdIdx]:null;
let weekly_stacked=Array.isArray(hist.weekly_stacked)?hist.weekly_stacked.map(x=>({...x})):[];
if(todayDayName){ const tot=todayIA+todayManual; const e={day:todayDayName,ia:todayIA,manual:todayManual,total:tot,pct_ia:tot>0?Math.round(todayIA/tot*100):0}; const i=weekly_stacked.findIndex(x=>x.day===todayDayName); if(i>=0) weekly_stacked[i]=e; else weekly_stacked.push(e); }
const weekIA=weekly_stacked.reduce((a,x)=>a+(x.ia||0),0);
const weekMa=weekly_stacked.reduce((a,x)=>a+(x.manual||0),0);

// Envejecidos (vivo)
const tickets_aged_3d=count(d.zd_aged);
const agedAll=results(d.zd_aged);
const aged_tickets_list=agedAll.filter(t=>t&&t.id).sort((a,b)=>new Date(a.created_at)-new Date(b.created_at)).map(t=>({ id:t.id, subject:t.subject||'(sin asunto)', status:t.status, priority:t.priority, created_at:t.created_at, updated_at:t.updated_at, organization_id:t.organization_id, requester_id:t.requester_id, assignee_id:t.assignee_id, age_days:t.created_at?Math.floor((Date.now()-new Date(t.created_at).getTime())/86400000):null, url:`https://soporteyurest.zendesk.com/agent/tickets/${t.id}` }));

// Incidencias dev (vivo)
const incidArr=results(d.zd_incidencias);
const incidencias_list=incidArr.map(t=>({ id:t.id, subject:t.subject||'(sin asunto)', status:t.status, priority:t.priority, created_at:t.created_at, updated_at:t.updated_at, organization_id:t.organization_id, requester_id:t.requester_id, assignee_id:t.assignee_id, age_days:t.created_at?Math.floor((Date.now()-new Date(t.created_at).getTime())/86400000):null, url:`https://soporteyurest.zendesk.com/agent/tickets/${t.id}` }));
const incidencias_buckets=(function(){ const b={lt30:0,b30_60:0,b60_100:0,gt100:0}; for(const t of incidArr){ if(!t||!t.created_at) continue; const age=Math.floor((Date.now()-new Date(t.created_at).getTime())/86400000); if(age<30)b.lt30++; else if(age<60)b.b30_60++; else if(age<100)b.b60_100++; else b.gt100++; } return b; })();

// orgs_by_open_count (vivo) — nombres de zd_orgs (abiertas)
const orgMap=new Map(); const orgsR=(d.zd_orgs&&Array.isArray(d.zd_orgs.organizations))?d.zd_orgs.organizations:[]; for(const o of orgsR){ if(o&&o.id) orgMap.set(o.id,o.name); }
function orgName(id){ return orgMap.get(id)||`Organización ${id}`; }
const openOrgCount=new Map();
for (const t of openRes){ if(!t.organization_id) continue; openOrgCount.set(t.organization_id,(openOrgCount.get(t.organization_id)||0)+1); }
const orgs_by_open_count={gt3:[],between_2_3:[],eq1:[]};
for (const [orgId,c] of openOrgCount.entries()){ const e={id:orgId,name:orgName(orgId),count:c}; if(c>3)orgs_by_open_count.gt3.push(e); else if(c>=2)orgs_by_open_count.between_2_3.push(e); else orgs_by_open_count.eq1.push(e); }
orgs_by_open_count.gt3.sort((a,b)=>b.count-a.count); orgs_by_open_count.between_2_3.sort((a,b)=>b.count-a.count); orgs_by_open_count.eq1.sort((a,b)=>b.count-a.count);
const orgs_by_open_count_summary={ gt3:orgs_by_open_count.gt3.length, between_2_3:orgs_by_open_count.between_2_3.length, eq1:orgs_by_open_count.eq1.length, total_orgs:openOrgCount.size };

return [{ json: {
  generated_at: new Date().toISOString(),
  _workflow_version: '2026-06-16-split-live',
  _hist_generated_at: hist.hist_generated_at || null,
  tickets_today: today,
  tickets_yesterday: hist.tickets_yesterday ?? null,
  tickets_week: week,
  tickets_last_week: hist.tickets_last_week ?? null,
  tickets_open: open,
  tickets_pending: pending,
  tickets_month: hist.tickets_month ?? null,
  tickets_solved_today: solvedToday,
  backlog_today: backlogToday,
  frt_avg_min: d.frt_avg_min ?? null,
  frt_sample: d.frt_sample ?? 0,
  frt_answered: d.frt_answered ?? 0,
  frt_pending: d.frt_pending ?? 0,
  frt_min: d._frt_min ?? null,
  frt_max: d._frt_max ?? null,
  frt_median: d._frt_median ?? null,
  frt_breakdown: d._frt_breakdown ?? [],
  tickets_aged_3d,
  tickets_incidencias_dev: count(d.zd_incidencias),
  aged_tickets_list,
  incidencias_list,
  incidencias_buckets,
  tickets_today_ia: todayIA,
  tickets_today_manual: todayManual,
  tickets_yesterday_ia: hist.tickets_yesterday_ia ?? null,
  tickets_yesterday_manual: hist.tickets_yesterday_manual ?? null,
  tickets_month_ia: hist.tickets_month_ia ?? null,
  tickets_month_manual: hist.tickets_month_manual ?? null,
  tickets_week_ia: weekIA,
  tickets_week_manual: weekMa,
  hourly_today,
  weekly_stacked,
  top_orgs: hist.top_orgs ?? [],
  tickets_by_type: hist.tickets_by_type ?? null,
  orgs_by_open_count_summary,
  orgs_by_open_count
} }];

// Disparado por Schedule Trigger: guarda payload SLIM en staticData.
// Slim = solo los campos que el frontend usa para pintar el dashboard.
// Campos pesados (listas de tickets, debug, breakdowns) NO se cachean;
// siguen disponibles en el output del nodo 'Agregar KPIs' para inspección
// vía Executions de n8n.
const full = $input.first().json || {};
const slim = {};
const KEEP = [
  // Meta
  'generated_at', '_workflow_version',
  // Counters
  'tickets_today', 'tickets_yesterday', 'tickets_week', 'tickets_last_week',
  'tickets_open', 'tickets_pending', 'tickets_month', 'tickets_solved_today',
  'tickets_today_ia', 'tickets_today_manual',
  'tickets_yesterday_ia', 'tickets_yesterday_manual',
  'tickets_week_ia', 'tickets_week_manual',
  'tickets_month_ia', 'tickets_month_manual',
  'backlog_today', 'tickets_aged_3d', 'tickets_incidencias_dev',
  // FRT (resumen, no breakdown)
  'frt_avg_min', 'frt_sample', 'frt_answered', 'frt_pending',
  'frt_min', 'frt_max', 'frt_median',
  // Charts y agrupaciones que pinta el frontend
  'hourly_today', 'weekly_stacked', 'top_orgs', 'tickets_by_type',
  'incidencias_buckets'
];
for (const k of KEEP) if (k in full) slim[k] = full[k];
const staticData = $getWorkflowStaticData('global');
staticData.cached_payload = slim;
staticData.cached_at      = new Date().toISOString();
const _sizeBytes = JSON.stringify(slim).length;
return [{ json: { saved: true, cached_at: staticData.cached_at, _slim_keys: Object.keys(slim).length, _size_bytes: _sizeBytes, _size_kb: Math.round(_sizeBytes/1024) } }];

// Disparado por el webhook: lee el último payload cacheado y lo emite tal cual.
// Si la caché está vacía (primer arranque o reset), devuelve estructura mínima con _stale=true.
const staticData = $getWorkflowStaticData('global');
const cached = staticData.cached_payload || null;
if (!cached) {
  return [{ json: {
    generated_at: null,
    cached_at: null,
    _stale: true,
    _hint: 'Cache vacía. Espera al primer tick del Schedule Trigger (5 min) o ejecútalo manualmente.',
    hourly_today: [],
    weekly_stacked: [],
    top_orgs: []
  } }];
}
return [{ json: { ...cached, cached_at: staticData.cached_at, _stale: false } }];
